SELECT level AS menu_level, A.*, (SELECT link_url FROM WB_MODULE_MNGT B WHERE A.module_idx = B.module_idx) AS link_url FROM ( SELECT menu_idx, parent_menu_idx, menu_url, menu_name, menu_desc, print_seq, menu_type, group_idx, module_idx, view_yn, CASE WHEN menu_type = 'FOLDER' THEN 1 ELSE 0 END AS load_on_demand FROM ( SELECT * FROM ( SELECT ( SELECT LISTAGG(auth_id,',') WITHIN GROUP (ORDER BY auth_id) FROM CMS_ADMIN_MENU_AUTH b WHERE (b.menu_idx = A.menu_idx) GROUP BY menu_idx) AS auth_list, (select min(auth_id) from cms_admin_menu_auth c where a.menu_idx = c.menu_idx group by menu_idx) as auth_id, a.* FROM CMS_ADMIN_MENU a ) WHERE instr(auth_list, #{auth_id}, 1) > 0 OR auth_list IS NULL OR auth_id >= ${auth_id}
) CMS_ADMIN_MENU WHERE use_yn = 'Y' AND view_yn != 'N' AND admin_access_yn = 'N'
AND menu_idx_list IN ( SELECT menu_idx FROM CMS_ADMIN_MENU_AUTH WHERE grp_seqno IN
#{item}
)
) A CONNECT BY PRIOR menu_idx = parent_menu_idx START WITH parent_menu_idx = 0 ORDER SIBLINGS BY print_seq

SELECT level AS menu_level, A.*, (SELECT link_url FROM WB_MODULE_MNGT B WHERE A.module_idx = B.module_idx) AS link_url FROM ( SELECT menu_idx, parent_menu_idx, menu_url, menu_name, menu_desc, print_seq, menu_type, group_idx, module_idx, view_yn, CASE WHEN menu_type = 'FOLDER' THEN 1 ELSE 0 END AS load_on_demand FROM CMS_ADMIN_MENU WHERE use_yn = 'Y' AND view_yn != 'N'
AND admin_access_yn = #{admin_access_yn}
) A
WHERE ( menu_idx in ( SELECT menu_idx FROM WB_MEMBER_GROUP_AUTH WHERE member_group_idx IN
#{i}
AND module_type = 'CMS' ) OR menu_idx in ( SELECT parent_menu_idx FROM CMS_ADMIN_MENU WHERE menu_idx IN ( SELECT menu_idx FROM WB_MEMBER_GROUP_AUTH WHERE member_group_idx IN
#{i}
AND module_type = 'CMS') ) OR menu_idx in ( SELECT parent_menu_idx FROM CMS_ADMIN_MENU WHERE menu_idx IN ( SELECT parent_menu_idx FROM CMS_ADMIN_MENU WHERE menu_idx IN ( SELECT menu_idx FROM WB_MEMBER_GROUP_AUTH WHERE member_group_idx IN
#{i}
AND module_type = 'CMS') ) )
)
CONNECT BY PRIOR menu_idx = parent_menu_idx START WITH parent_menu_idx = 0 ORDER SIBLINGS BY print_seq

