SELECT NVL(MAX(menu_idx),0)+1 FROM CMS_ADMIN_MENU
INSERT INTO CMS_ADMIN_MENU ( menu_idx, parent_menu_idx, menu_url, menu_name, menu_desc, menu_type, use_yn, view_yn, print_seq, add_date, modify_date, module_idx, group_idx, menu_full_path_name ) VALUES ( #{menu_idx} , #{parent_menu_idx}, #{menu_url}, #{menu_name}, #{menu_desc}, #{menu_type}, #{use_yn}, #{view_yn}, #{print_seq}, SYSDATE, SYSDATE, #{module_idx},
#{menu_idx}, #{menu_name}
#{group_idx}, ( SELECT LTRIM(SYS_CONNECT_BY_PATH(menu_name,' > '),' >') || ' > ' || #{menu_name} AS menu_full_path_name FROM CMS_ADMIN_MENU WHERE menu_idx = #{parent_menu_idx} CONNECT BY PRIOR menu_idx = parent_menu_idx START WITH parent_menu_idx = 0 )
)

