module_idx = #{module_idx},
use_yn = #{use_yn}, view_yn = #{view_yn}, admin_access_yn = #{admin_access_yn}, print_seq = #{print_seq}, modify_date = SYSDATE, menu_full_path_name =
#{menu_name}
( SELECT LTRIM(SYS_CONNECT_BY_PATH(menu_name,' > '),' >') || ' > ' || #{menu_name} AS menu_full_path_name FROM CMS_ADMIN_MENU WHERE menu_idx = #{parent_menu_idx} CONNECT BY PRIOR menu_idx = parent_menu_idx START WITH parent_menu_idx = 0 )
WHERE menu_idx = #{menu_idx}

